// Filter for installments due within 7 days
// Since we don't have a due_date column, we check 30 days from creation
const now = new Date();
const items = $input.all();
const results = [];

for (const item of items) {
  const createdAt = new Date(item.json.created_at);
  // Installment 2 is due 30 days after installment 1 creation
  const dueDate = new Date(createdAt.getTime() + 30 * 24 * 60 * 60 * 1000);
  const daysUntilDue = Math.ceil((dueDate.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));

  if (daysUntilDue === 7 || daysUntilDue === 3 || daysUntilDue === 1) {
    results.push({
      json: {
        ...item.json,
        due_date: dueDate.toISOString().split('T')[0],
        days_until_due: daysUntilDue,
        reminder_type: daysUntilDue === 1 ? 'final' : daysUntilDue === 3 ? 'urgent' : 'upcoming'
      }
    });
  }
}

if (results.length === 0) {
  // Return empty to stop execution
  return [{ json: { no_reminders: true } }];
}

return results;

const payment = $('Filter Due Soon').item.json;
const profileData = $input.first().json;
const profile = Array.isArray(profileData) ? profileData[0] : profileData;

const firstName = profile?.first_name || 'Student';
const email = profile?.email || '';
const phone = profile?.phone || '';
const amount = (payment.amount_cents / 100).toFixed(2);
const dueDate = payment.due_date;
const daysLeft = payment.days_until_due;

let urgencyText = '';
if (daysLeft === 1) {
  urgencyText = 'FINAL REMINDER: Your payment is due tomorrow.';
} else if (daysLeft === 3) {
  urgencyText = `Your payment is due in ${daysLeft} days.`;
} else {
  urgencyText = `Your payment is due in ${daysLeft} days.`;
}

return [{
  json: {
    first_name: firstName,
    email: email,
    phone: phone,
    amount: `$${amount}`,
    amount_cents: payment.amount_cents,
    due_date: dueDate,
    days_until_due: daysLeft,
    urgency_text: urgencyText,
    reminder_type: payment.reminder_type,
    user_id: payment.user_id
  }
}];

